ALTER TABLE concierge_services CHANGE COLUMN available_quantity daily_quota int NOT NULL DEFAULT -1;

CREATE TABLE IF NOT EXISTS concierge_quota_usage (
  id int AUTO_INCREMENT PRIMARY KEY,
  concierge_service_id int NOT NULL,
  usage_date varchar(10) NOT NULL,
  used_quota int NOT NULL DEFAULT 0,
  updated_at timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT fk_quota_service FOREIGN KEY (concierge_service_id) REFERENCES concierge_services(id) ON DELETE CASCADE
);

CREATE INDEX idx_quota_service_date ON concierge_quota_usage(concierge_service_id, usage_date);

